const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const Redis = require('ioredis');
const twilio = require('twilio');

const app = express();
app.use(bodyParser.json());

const redis = new Redis(process.env.REDIS_URL);
const twilioClient = twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);

const TWILIO_FROM = process.env.TWILIO_FROM_NUMBER;
const CODE_TTL_SECONDS = 10 * 60;
const MAX_ATTEMPTS = 10;

function generate6DigitCode() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

function codeKey(userId) {
  return `2fa:code:${userId}`;
}

function attemptsKey(userId) {
  return `2fa:attempts:${userId}`;
}

function lockKey(userId) {
  return `2fa:lock:${userId}`;
}

async function sendVerificationCode(userId, phoneNumber) {
  const code = generate6DigitCode();
  const payload = JSON.stringify({
    code,
    createdAt: Date.now()
  });

  await redis.set(codeKey(userId), payload, 'EX', CODE_TTL_SECONDS);
  await redis.del(attemptsKey(userId));
  await redis.del(lockKey(userId));

  await twilioClient.messages.create({
    body: `Your verification code is ${code}. It expires in 10 minutes.`,
    from: TWILIO_FROM,
    to: phoneNumber
  });

  return true;
}

app.post('/2fa/send', async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;

    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'userId and phoneNumber are required' });
    }

    await sendVerificationCode(userId, phoneNumber);
    return res.json({ success: true, message: 'Verification code sent' });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/2fa/verify', async (req, res) => {
  try {
    const { userId, code } = req.body;

    if (!userId || !code) {
      return res.status(400).json({ error: 'userId and code are required' });
    }

    const locked = await redis.get(lockKey(userId));
    if (locked) {
      return res.status(423).json({ error: 'Account locked due to too many attempts' });
    }

    const stored = await redis.get(codeKey(userId));
    if (!stored) {
      return res.status(400).json({ error: 'Code expired or not found' });
    }

    const data = JSON.parse(stored);
    const attempts = await redis.incr(attemptsKey(userId));
    if (attempts === 1) {
      await redis.expire(attemptsKey(userId), CODE_TTL_SECONDS);
    }

    if (attempts > MAX_ATTEMPTS) {
      await redis.set(lockKey(userId), '1', 'EX', CODE_TTL_SECONDS);
      await redis.del(codeKey(userId));
      return res.status(423).json({ error: 'Account locked due to too many attempts' });
    }

    if (String(code) !== String(data.code)) {
      return res.status(401).json({ error: 'Invalid code', remainingAttempts: Math.max(0, MAX_ATTEMPTS - attempts) });
    }

    await redis.del(codeKey(userId));
    await redis.del(attemptsKey(userId));

    const accessToken = crypto.randomBytes(32).toString('hex');
    return res.json({ success: true, accessToken });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to verify code' });
  }
});

